import os
from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core
from src.utils.prism_config import get_asset_folder_path, resolve_cfg

class PrismGetAssetTypeByNameNode(BaseNode):
    name = 'Prism: Get Asset Type by Name'
    category = 'DCCs'

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = 'icons/prism_icon.png'
        self.add_input('core',    'any')
        self.add_input('project', 'dict')
        self.add_input('name',    'string', widget_type='text', default='')
        self.add_output('asset_type', 'dict')
        self.add_output('entity',     'dict')
        self.add_output('matches',    'list')
        self.add_output('found',      'bool')

    def _project_path(self, project):
        path = project.get('project_path', '')
        if not path:
            cfg = project.get('configPath', '')
            if cfg:
                path = os.path.dirname(os.path.dirname(cfg))
        return path

    def _switch_project(self, core, project):
        path = self._project_path(project)
        if not path:
            self.log_error('Cannot determine project path from project dict.')
            return False
        try:
            core.changeProject(path)
            return True
        except Exception as e:
            self.log_error(f'changeProject failed: {e}')
            return False

    def _category(self, asset):
        p = asset.get('asset_path', asset.get('name', ''))
        return p.replace('\\\\', '/').split('/')[0] if p else ''

    def _build_asset_type(self, cat_name, project_path, core=None, cfg_path=None):
        assets_root = get_asset_folder_path(project_path, core=core, cfg_path=cfg_path)
        folder_path = os.path.join(assets_root, cat_name) if assets_root else ''
        return {'type': 'asset_type', 'name': cat_name, 'path': folder_path}

    async def execute(self, inputs):
        core    = resolve_prism_core(inputs)
        project = inputs.get('project') or {}
        name    = (inputs.get('name') or '').strip()

        empty = {'asset_type': {}, 'entity': {}, 'matches': [], 'found': False}
        if core is None:
            self.log_error('No PrismCore found.')
            return empty
        if not project:
            self.log_error('No project provided.')
            return empty
        if not self._switch_project(core, project):
            return empty

        try:
            all_assets = list(core.entities.getAssets() or [])
        except Exception as e:
            self.log_error(f'getAssets failed: {e}')
            return empty

        # Collect unique categories preserving original casing from first occurrence
        seen = {}
        for a in all_assets:
            cat = self._category(a)
            if cat and cat.lower() not in seen:
                seen[cat.lower()] = cat

        proj_path = self._project_path(project)
        cfg_path  = resolve_cfg(core=core)

        name_lower = name.lower()
        matches = [
            self._build_asset_type(orig, proj_path, core=core, cfg_path=cfg_path)
            for key, orig in seen.items()
            if not name or key == name_lower
        ]

        if not matches:
            self.log_error(f"Asset type '{name}' not found. Available: {sorted(seen.values())}")
            return empty

        best = matches[0]
        self.log_info(f"Found {len(matches)} asset type(s) matching '{name}': {[m['name'] for m in matches]}")
        return {'asset_type': best, 'entity': best, 'matches': matches, 'found': True}

def register_node():
    return PrismGetAssetTypeByNameNode
